from dataclasses import dataclass, field
from datetime import date
from typing import Optional

@dataclass
class ScorecardDimension:
    name: str
    weight: float          # 0.0–1.0; all weights must sum to 1.0
    raw_score: float       # 0.0–100.0
    evidence: list[str] = field(default_factory=list)

    @property
    def weighted(self) -> float:
        return self.raw_score * self.weight


@dataclass
class PartnerScorecard:
    msp_name: str
    period_end: date
    dimensions: list[ScorecardDimension]
    notes: str = ""

    @property
    def composite_score(self) -> float:
        return sum(d.weighted for d in self.dimensions)

    @property
    def rating(self) -> str:
        s = self.composite_score
        if s >= 85: return "GREEN"
        if s >= 70: return "AMBER"
        return "RED"

    def remediation_required(self) -> bool:
        return self.rating == "RED"

    def dimensions_below(self, threshold: float) -> list[ScorecardDimension]:
        return [d for d in self.dimensions if d.raw_score < threshold]

    def summary(self) -> str:
        lines = [
            f"Partner: {self.msp_name}  Period: {self.period_end}",
            f"Composite: {self.composite_score:.1f}/100  Rating: {self.rating}",
        ]
        weak = self.dimensions_below(70.0)
        if weak:
            lines.append("Dimensions below 70:")
            for d in weak:
                lines.append(f"  {d.name}: {d.raw_score:.0f}/100")
        return "\n".join(lines)


def build_monthly_scorecard(
    msp_name: str,
    period_end: date,
    defect_escape_pct: float,       # lower is better
    availability_pct: float,         # higher is better (target 99.9)
    critical_vulns_open: int,        # lower is better
    escalation_response_hrs: float,  # lower is better (target ≤4 h)
    invoice_accuracy_pct: float,     # higher is better
) -> PartnerScorecard:

    def delivery_score(defect_pct: float) -> float:
        # 0 defects → 100; 5% defects → 0
        return max(0.0, 100.0 - defect_pct * 20)

    def sla_score(avail: float) -> float:
        # 100% → 100; 99.0% → 0; below 99.0 → capped at 0
        return max(0.0, (avail - 99.0) / 1.0 * 100)

    def security_score(vulns: int) -> float:
        return max(0.0, 100.0 - vulns * 15)

    def comms_score(response_hrs: float) -> float:
        return max(0.0, 100.0 - max(0, response_hrs - 4) * 10)

    return PartnerScorecard(
        msp_name=msp_name,
        period_end=period_end,
        dimensions=[
            ScorecardDimension("Delivery Quality", 0.30,
                delivery_score(defect_escape_pct), [f"Defect escape: {defect_escape_pct}%"]),
            ScorecardDimension("SLA Compliance", 0.25,
                sla_score(availability_pct), [f"Availability: {availability_pct}%"]),
            ScorecardDimension("Security Posture", 0.20,
                security_score(critical_vulns_open), [f"Critical CVEs open: {critical_vulns_open}"]),
            ScorecardDimension("Communication", 0.15,
                comms_score(escalation_response_hrs), [f"Escalation response: {escalation_response_hrs}h"]),
            ScorecardDimension("Commercial Accuracy", 0.10,
                invoice_accuracy_pct, [f"Invoice accuracy: {invoice_accuracy_pct}%"]),
        ]
    )


# Example usage
sc = build_monthly_scorecard(
    msp_name="AcmeMSP",
    period_end=date(2025, 6, 30),
    defect_escape_pct=1.5,
    availability_pct=99.85,
    critical_vulns_open=0,
    escalation_response_hrs=2.5,
    invoice_accuracy_pct=98.0,
)
print(sc.summary())
# Partner: AcmeMSP  Period: 2025-06-30
# Composite: 86.8/100  Rating: GREEN
